' \
        query="select serialno,contracttype,guarantytype,contractstatus,replace(replace(contractno,chr(10),''),chr(13),'') as contractno,signdate,begindate,enddate,customerid,guarantorid,replace(replace(guarantorname,chr(10),''),chr(13),'') as guarantorname,creditorgid,replace(replace(creditorgname,chr(10),''),chr(13),'') as creditorgname,guarantycurrency,guarantyvalue,replace(replace(guarantyinfo,chr(10),''),chr(13),'') as guarantyinfo,replace(replace(otherdescribe,chr(10),''),chr(13),'') as otherdescribe,checkguaranty,replace(replace(reception,chr(10),''),chr(13),'') as reception,replace(replace(receptionduty,chr(10),''),chr(13),'') as receptionduty,replace(replace(guaranryopinion,chr(10),''),chr(13),'') as guaranryopinion,replace(replace(checkguarantyman1,chr(10),''),chr(13),'') as checkguarantyman1,replace(replace(checkguarantyman2,chr(10),''),chr(13),'') as checkguarantyman2,inputorgid,inputuserid,inputdate,updateuserid,updatedate,replace(replace(remark,chr(10),''),chr(13),'') as remark,certtype,certid,replace(replace(othername,chr(10),''),chr(13),'') as othername,loancardno,guaranteeform,commondate,bailratio,vouchtype,econtracttype,ectempsaveflag,replace(replace(textcontractno,chr(10),''),chr(13),'') as textcontractno,replace(replace(shortorg,chr(10),''),chr(13),'') as shortorg,replace(replace(orgname,chr(10),''),chr(13),'') as orgname,replace(replace(partyaaddress,chr(10),''),chr(13),'') as partyaaddress,partyaphone,partyafax,partyaprincipal,partyaduty,replace(replace(partybname,chr(10),''),chr(13),'') as partybname,partybcerttype,partybcertid,replace(replace(partybaddress,chr(10),''),chr(13),'') as partybaddress,partybphone,partybfax,replace(replace(partyblegalperson,chr(10),''),chr(13),'') as partyblegalperson,partybpostcode,partybduty,replace(replace(textmaincontractno,chr(10),''),chr(13),'') as textmaincontractno,guarantyrange,replace(replace(otherguarantyrange,chr(10),''),chr(13),'') as otherguarantyrange,guarantyperiod,replace(replace(otherguarantyperiod1,chr(10),''),chr(13),'') as otherguarantyperiod1,replace(replace(otherguarantyperiod2,chr(10),''),chr(13),'') as otherguarantyperiod2,notarizationflag,replace(replace(otherpromise,chr(10),''),chr(13),'') as otherpromise,replace(replace(otherparties,chr(10),''),chr(13),'') as otherparties,replace(replace(maincontractname,chr(10),''),chr(13),'') as maincontractname,maincontractcurrency,maincontractsum,compensatetype,replace(replace(transfercreditrange,chr(10),''),chr(13),'') as transfercreditrange,begintime,endtime,replace(replace(financeitem7,chr(10),''),chr(13),'') as financeitem7,replace(replace(financeitem6,chr(10),''),chr(13),'') as financeitem6,guarantytype2,printflag,pigeonholedate,quoteguarantyquota,quoteguarantyquotano,replace(replace(totalcopies,chr(10),''),chr(13),'') as totalcopies,replace(replace(partyacopies,chr(10),''),chr(13),'') as partyacopies,contractword,contractno1,contractname,currency1,contractsum1,contractword2,contractno2,contractname2,currency2,contractsum2,currency3,contractsum3,currency4,contractsum4,firstcreditparty,firstcreditcurrency,firstcreditsum,secondcreditparty,secondcreditcurrency,secondcreditsum,thirdcreditparty,thirdcreditcurrency,thirdcreditsum,preserialno,isinuse,replace(replace(ypguarantorid,chr(10),''),chr(13),'') as ypguarantorid,registationcode,residentflag,iscustody,obligeeid,obligeename,issaveowner,start_dt,end_dt,id_mark,etl_timestamp from iol.crss_guaranty_contract where start_dt between to_date('${batch_date}', 'yyyymmdd') - 6 and to_date('${batch_date}', 'yyyymmdd');" \
